var expect = require('expect.js');
var CreateResource = require('../../res/page/createresource/createresource');

describe('sqlscan-createresource', function(){
  this.timeout(5000);
  var _FileReader = window.FileReader;
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
    window.FileReader = _FileReader;
  });
  describe('#init createresource()', function(){
    it('init createresource', function(done){
      var createresource = CreateResource._create({
        events : {
          'afterrender' : function(){
            expect(createresource).to.be.ok();
            expect(createresource._container).to.be.ok();
            createresource._container.on('aftercomplete', function(){
              var scriptName = this.query('field[name=scriptName]');
              expect(scriptName).to.be.ok();
              var scriptType = this.query('combobox[name=scriptType]');
              expect(scriptType).to.be.ok();
              // expect(scriptType.data.records.length).to.be(4);
              var scriptDesc = this.query('textareafield[name=scriptDesc]');
              expect(scriptDesc).to.be.ok();
              done();
            });
          }
        }
      });
    });
  });
  describe('#createresource change events', function(){
    it('createresource change events', function(done){
      var createresource = CreateResource._create({
        events : {
          'afterrender' : function(){
            expect(createresource).to.be.ok();
            expect(createresource._container).to.be.ok();
            createresource._container.on('aftercomplete', function(){
              var upload = $('.sqlScanUploadFile>input');
              var type = this.query('combobox[name=scriptType]');
              expect($('.sqlScanUploadFile>label').html()).to.be('* 请选择文件');
              upload.trigger('change');
              expect($('.sqlScanUploadFile>label').html()).to.be('* 请选择文件');
              this.fileValueTest = 'txt';
              type.val('sh');
              upload.trigger('change');
              expect($('.sqlScanUploadFile>label').html()).to.be('* 文件需与脚本类型相同');
              this.fileValueTest = 11 * 1024 * 1024;
              type.val(this.fileValueTest);
              upload.trigger('change');
              expect($('.sqlScanUploadFile>label').html()).to.be('* 文件不能超过10M');
              done();
            });
          }
        }
      });
    });
  });
  describe('#createresource events', function(){
    it('createresource events', function(done){
      var FileReader = function(){};
      FileReader.prototype.readAsText = function(file){
        return file;
      }
      window.FileReader = FileReader;
      var createresource = CreateResource._create({
        events : {
          'afterrender' : function(){
            expect(createresource).to.be.ok();
            expect(createresource._container).to.be.ok();
            createresource._container.on('aftercreateresource', function(){
              var resourceLabel = $('#sqlScanResourceId');
              expect(this.checkValueTest).to.be('资源创建成功');
            });
            createresource._container.on('aftercomplete', function(){
              var upload = $('.sqlScanUploadFile>input');
              var btnCreateResourceSure = this.query('button[name="btnCreateResourceSure"]');
              expect(this.checkValueTest).not.to.be.ok();
              btnCreateResourceSure.emit('click');
              expect(this.checkValueTest).to.be('参数输入不正确');

              var name = this.query('field[name=scriptName]');
              var file = $('.sqlScanUploadFile>input');
              var type = this.query('combobox[name=scriptType]');
              var desc = this.query('textareafield[name=scriptDesc]');
              name.val('test');
              file.val('sh');
              this.fileValueTest = ['sh','sh'];
              type.val('sh');
              desc.val('testdesc');
              file[0].files = [{name : 'testfile.sh'}];
              btnCreateResourceSure.emit('click');
              expect(this.checkValueTest).to.be(null);
              //console.log($('.sqlScanUploadFile>label').html())
              /*var scriptName = this.query('field[name=scriptName]');
              expect(scriptName).to.be.ok();
              var scriptType = this.query('combobox[name=scriptType]');
              expect(scriptType).to.be.ok();
              // expect(scriptType.data.records.length).to.be(4);
              var scriptDesc = this.query('textareafield[name=scriptDesc]');
              expect(scriptDesc).to.be.ok();*/
              done();
            });
          }
        }
      });
    });
  });
});